    public static void main(String[] args){
        Scanner sc=new Scanner(System.in);
        int q=sc.nextInt(); sc.nextLine();
        Deque<int[]> st=new ArrayDeque<>();  // [val, min]
        StringBuilder sb=new StringBuilder();
        while(q-->0){
            String line=sc.nextLine();
            String[] parts=line.split(" ");
            switch(parts[0]){
                case "PUSH":
                    int x=Integer.parseInt(parts[1]);
                    int mn=st.isEmpty()?x:Math.min(x,st.peek()[1]);
                    st.push(new int[]{x,mn}); break;
                case "POP":
                    if(!st.isEmpty()) st.pop(); break;
                case "TOP":
                    sb.append(st.isEmpty()?-1:st.peek()[0]).append("\n"); break;
                case "MIN":
                    sb.append(st.isEmpty()?-1:st.peek()[1]).append("\n"); break;
            }
        }
        System.out.print(sb);
    }
}

